#include<bits/stdc++.h>
using namespace std;
int main(){
    int a[5],b,c,d=0;
    for(int i=0;i<5;i++){
		cin>>a[i];
	}
	for(int i=0;i<5;i++){
		b=i-1;
		c=i+1;
		if(b==-1){
			b=4;}
		if(c==5){
			c=0;}
		a[b]=a[b]+a[i]/3;
		a[c]+=a[i]/3;
		d+=a[i]%3;
		a[i]=a[i]/3;
		}
	for(int i=0;i<5;i++){
		cout<<a[i]<<" ";
		
	}
	cout<<endl<<d;
	return 0;
}
